CREATE TABLE IF NOT EXISTS posters_poster (id BIGINT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(150) NOT NULL,subtitle VARCHAR(300) NOT NULL DEFAULT '',image VARCHAR(100) NOT NULL,link VARCHAR(500) NOT NULL DEFAULT '',page VARCHAR(20) NOT NULL DEFAULT 'home',slot VARCHAR(30) NOT NULL,sort_order INT UNSIGNED NOT NULL DEFAULT 0,starts_at DATETIME(6) NULL,ends_at DATETIME(6) NULL,is_active BOOLEAN NOT NULL DEFAULT TRUE,created_at DATETIME(6) NOT NULL,updated_at DATETIME(6) NOT NULL,INDEX poster_position_idx(page,slot,is_active)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
